// === КОНФИГ ===
const BASE_URL = 'https://api.sgnl.pro/public/v1';

// Заполните свои значения
const CLIENT_ID = "YOUR_CLIENT_ID";
const CLIENT_SECRET = "YOUR_CLIENT_SECRET";

// Что ищем
const PROJECT_NAME = $input.first().json.project_name;
const FOLDER_NAME_RAW = ($input.first().json.folder_name ?? '').toString();
const FILE_NAME_RAW = ($input.first().json.file_name ?? '').toString();

// Нужные скоупы
const SCOPES_ARRAY = [
  'project:read', 'project:list',
  'docs:folder:read', 'docs:folder:list',
  'docs:item:read', 'docs:item:list',
  'docs:version:read', 'docs:version:list',
  'docs:object:read', 'docs:object:list',
];

// === УТИЛИТЫ ===
const normalize = (s) => (s ?? '').toString().trim();
const sameName = (a, b) => normalize(a).toLowerCase() === normalize(b).toLowerCase();
const splitPath = (p) =>
  normalize(p)
    .replaceAll('\\', '/')       // поддержка обратного слеша
    .split('/')
    .map((x) => x.trim())
    .filter(Boolean);

// === HTTP-ОБЁРТКИ ===
const httpJsonLenient = async (method, url, { headers = {}, body } = {}) =>
  await this.helpers.httpRequest({
    method,
    url,
    headers: { accept: 'application/json', ...headers },
    body,
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusCode: true,
  });

const httpJson = async (method, url, { headers = {}, body } = {}) =>
  await this.helpers.httpRequest({
    method,
    url,
    headers: { accept: 'application/json', ...headers },
    body,
    json: true,
  });

// === АВТОРИЗАЦИЯ СО СКОУПАМИ ===
const getToken = async () => {
  const url = `${BASE_URL}/auth/token`;
  const res = await httpJsonLenient('POST', url, {
    body: { clientId: CLIENT_ID, clientSecret: CLIENT_SECRET, scopes: SCOPES_ARRAY },
  });
  if (!(res.statusCode >= 200 && res.statusCode < 300 && res.body?.token)) {
    throw new Error(`Auth failed: ${res.statusCode} ${JSON.stringify(res.body || {})}`);
  }
  return res.body.token;
};

// === БИЗНЕС-ЛОГИКА ===
const getProjectByName = async (jwt, name) => {
  const url = `${BASE_URL}/projects`;
  const res = await httpJson('GET', url, { headers: { Authorization: `Bearer ${jwt}` } });
  const projects = Array.isArray(res) ? res : res?.projects || res?.data || [];
  const project = projects.find(p => sameName(p?.name, name));
  if (!project) throw new Error(`Проект "${name}" не найден.`);
  if (!project.id) throw new Error(`У проекта "${name}" отсутствует id.`);
  return project;
};

const getRootFolderId = async (jwt, projectId) => {
  const url = `${BASE_URL}/docs/projects/${encodeURIComponent(projectId)}`;
  const res = await httpJson('GET', url, { headers: { Authorization: `Bearer ${jwt}` } });
  const rootFolderId = res?.rootFolderId || res?.id || res?.folder?.id;
  if (!rootFolderId) throw new Error('Не удалось определить ID корневой папки документов проекта.');
  return rootFolderId;
};

const listChildFolders = async (jwt, parentFolderId) => {
  const url = `${BASE_URL}/folders/${encodeURIComponent(parentFolderId)}/children`;
  const res = await httpJson('GET', url, { headers: { Authorization: `Bearer ${jwt}` } });
  return Array.isArray(res) ? res : res?.folders || res?.data || [];
};

const getChildFolderByName = async (jwt, parentFolderId, folderName) => {
  const children = await listChildFolders(jwt, parentFolderId);
  const folder = children.find(f => sameName(f?.name, folderName));
  if (!folder) throw new Error(`Папка "${folderName}" не найдена среди дочерних у ${parentFolderId}.`);
  if (!folder.id) throw new Error(`У папки "${folderName}" отсутствует id.`);
  return folder;
};

/**
 * Рекурсивный проход по пути папок:
 * path может быть: "Папка1/Папка2/Папка3" или "Папка1\\Папка2\\Папка3"
 * Возвращает объект конечной папки.
 */
const getFolderByPath = async (jwt, startFolderId, path) => {
  const parts = splitPath(path);
  let currentId = startFolderId;
  let current = { id: startFolderId };

  for (const part of parts) {
    current = await getChildFolderByName(jwt, currentId, part);
    currentId = current.id;
  }
  return current;
};

const listItemsInFolder = async (jwt, folderId) => {
  const url = `${BASE_URL}/items?folderId=${encodeURIComponent(folderId)}`;
  const res = await httpJson('GET', url, { headers: { Authorization: `Bearer ${jwt}` } });
  return Array.isArray(res) ? res : res?.items || res?.data || [];
};

const getItemByName = async (jwt, folderId, fileName) => {
  const items = await listItemsInFolder(jwt, folderId);
  const item = items.find(i => sameName(i?.name, fileName));
  if (!item) {
    const names = items.map(i => i?.name).filter(Boolean).join(', ');
    throw new Error(`Файл "${fileName}" не найден в папке ${folderId}. Доступные: ${names || 'пусто'}`);
  }
  if (!item.id) throw new Error(`У файла "${fileName}" отсутствует item.id.`);
  const versionId = item.topVersionId;
  if (!versionId) throw new Error(`Не удалось определить versionId для файла "${fileName}".`);
  return { itemId: item.id, versionId, itemName: item.name };
};

const getDownloadUrl = async (jwt, itemId, versionId) => {
  const url = `${BASE_URL}/items/download?itemId=${encodeURIComponent(itemId)}&versionId=${encodeURIComponent(versionId)}`;
  const res = await httpJson('GET', url, { headers: { Authorization: `Bearer ${jwt}` } });
  if (!res?.signedUrl) throw new Error('Не удалось получить ссылку на скачивание (signedUrl).');
  return res.signedUrl;
};

// === ОСНОВНОЙ БЛОК ===
try {
  const jwt = await getToken();
  const project = await getProjectByName(jwt, PROJECT_NAME);
  const rootFolderId = await getRootFolderId(jwt, project.id);

  // Поддерживаем два способа:
  // 1) folder_name = "Папка1/Папка2/Папка3", file_name = "Файл.docx"
  // 2) folder_name = "", file_name = "Папка1/Папка2/Папка3/Файл.docx"
  const folderPath = FOLDER_NAME_RAW;
  const filePathParts = splitPath(FILE_NAME_RAW);

  let targetFolder;
  let targetFileName;

  if (folderPath) {
    // Вариант 1: путь папки в FOLDER_NAME_RAW
    targetFolder = await getFolderByPath(jwt, rootFolderId, folderPath);
    targetFileName = filePathParts.length > 1
      ? filePathParts[filePathParts.length - 1] // вдруг в file_name тоже дали путь — берём последний сегмент как имя файла
      : FILE_NAME_RAW;
  } else if (filePathParts.length > 1) {
    // Вариант 2: весь путь вместе с файлом в FILE_NAME_RAW
    const folderOnlyPath = filePathParts.slice(0, -1).join('/');
    targetFileName = filePathParts[filePathParts.length - 1];
    targetFolder = await getFolderByPath(jwt, rootFolderId, folderOnlyPath);
  } else {
    // Не дали путь вовсе — ищем файл в корне документов проекта
    targetFolder = { id: rootFolderId, name: 'root' };
    targetFileName = FILE_NAME_RAW;
  }

  const { itemId, versionId, itemName } = await getItemByName(jwt, targetFolder.id, targetFileName);
  const downloadUrl = await getDownloadUrl(jwt, itemId, versionId);
  const file = await httpJson('GET', downloadUrl);

  return [
    {
      json: {
        success: true,
        projectId: project.id,
        projectName: project.name,
        folderId: targetFolder.id,
        folderPathResolved: folderPath || filePathParts.slice(0, -1).join('/'),
        fileNameResolved: itemName,
        itemId,
        versionId,
        downloadUrl,
        file,
      }
    },
  ];
} catch (e) {
  return [
    {
      json: {
        success: false,
        message: e.message || String(e),
        stack: e.stack || null,
      },
    },
  ];
}

// Берем исходные данные из items
const data = items.map(item => item.json);

// Чистим ключи от переносов строк
const cleanedData = data.map(row => {
  const newRow = {};
  for (const key in row) {
    const cleanKey = key.replace(/[\r\n]/g, ' ').trim();
    newRow[cleanKey] = row[key];
  }
  return newRow;
});

// Сортируем по дате
cleanedData.sort((a, b) => {
  const dateA = a['SIGNAL Completed'] || '';
  const dateB = b['SIGNAL Completed'] || '';

  const parseDate = str => {
    const parts = str.split('.');
    if (parts.length !== 3) return new Date(0);
    return new Date(parts[2], parts[1]-1, parts[0]);
  };

  return parseDate(dateA) - parseDate(dateB);
});

// Возвращаем для следующего узла
return cleanedData.map(row => ({ json: row }));

